 19→class StatsLinkHandler
 20→@Inject constructor(
 21→    private val deepLinkUriUtils: DeepLinkUriUtils,
 22→    private val jetpackFeatureRemovalPhaseHelper: JetpackFeatureRemovalPhaseHelper
 23→) : DeepLinkHandler {
 24→    /**
 25→     * Builds navigate action from URL like:
 26→     * https://wordpress.com/stats/$timeframe/$site
 27→     * where timeframe and site are optional
 28→     * or
 29→     * wordpress://stats
 30→     */
 31→    override fun buildNavigateAction(uri: UriWrapper): NavigateAction {
 32→        val pathSegments = uri.pathSegments
 33→        val length = pathSegments.size
 34→        val site = pathSegments.getOrNull(length - 1)?.toSite()
 35→        val statsTimeframe = pathSegments.getOrNull(length - 2)?.toStatsTimeframe()
 36→        return when {
 37→            jetpackFeatureRemovalPhaseHelper.shouldShowStaticPage() -> OpenJetpackStaticPosterView
 38→            site != null && statsTimeframe != null -> {
 39→                OpenStatsForSiteAndTimeframe(site, statsTimeframe)
 40→            }
 41→            site != null -> {
 42→                OpenStatsForSite(site)
 43→            }
 44→            statsTimeframe != null -> {
 45→                OpenStatsForTimeframe(statsTimeframe)
 46→            }
 47→            else -> {
 48→                // In other cases, launch stats with the current selected site.
 49→                OpenStats
 50→            }
 51→        }
 52→    }
 53→
 54→    /**
 55→     * Returns true if the URI should be handled by StatsLinkHandler.
 56→     * The handled links are `https://wordpress.com/stats/day/$site` and `wordpress://stats`
 57→     */
 58→    override fun shouldHandleUrl(uri: UriWrapper): Boolean {
 59→        return (uri.host == HOST_WORDPRESS_COM &&
 60→                uri.pathSegments.firstOrNull() == STATS_PATH) || uri.host == STATS_PATH
 61→    }
 62→
 63→    override fun stripUrl(uri: UriWrapper): String {
 64→        return buildString {
 65→            val offset = if (uri.host == STATS_PATH) {
 66→                append(APPLINK_SCHEME)
 67→                0
 68→            } else {
 69→                append("$HOST_WORDPRESS_COM/")
 70→                1
 71→            }
 72→            append(STATS_PATH)
 73→            val pathSegments = uri.pathSegments
 74→            val size = pathSegments.size
 75→            val statsTimeframe = if (size > offset) pathSegments.getOrNull(offset) else null
 76→            val hasSiteUrl = if (size > offset + 1) pathSegments.getOrNull(offset + 1) != null else false
 77→            if (statsTimeframe != null) {
 78→                append("/$statsTimeframe")
 79→            }
 80→            if (hasSiteUrl) {
 81→                append("/$SITE_DOMAIN")
 82→            }
 83→        }
 84→    }
 85→
 86→    /**
 87→     * Converts HOST name of a site to SiteModel. It finds the Site in the current local sites and matches the name
 88→     * to the host.
 89→     */
 90→    private fun String.toSite(): SiteModel? {
 91→        return deepLinkUriUtils.hostToSite(this)
 92→    }
 93→
 94→    private fun String.toStatsTimeframe(): StatsTimeframe? {
 95→        return when (this) {
 96→            "day" -> StatsTimeframe.DAY
 97→            "week" -> StatsTimeframe.WEEK
 98→            "month" -> StatsTimeframe.MONTH
 99→            "year" -> StatsTimeframe.YEAR
100→            "insights" -> StatsTimeframe.INSIGHTS
101→            else -> null
102→        }
103→    }
104→
105→    companion object {
106→        private const val STATS_PATH = "stats"
107→    }
108→}
