 14→public class ReaderTag implements Serializable, FilterCriteria {
 15→    public static final String FOLLOWING_PATH = "/read/following";
 16→    public static final String LIKED_PATH = "/read/liked";
 17→    public static final String DISCOVER_PATH = String.format(Locale.US, "read/sites/%d/posts",
 18→            ReaderConstants.DISCOVER_SITE_ID);
 19→
 20→    public static final String TAG_TITLE_FOLLOWED_SITES = "Followed Sites";
 21→    public static final String TAG_SLUG_P2 = "p2";
 22→    public static final String TAG_SLUG_BOOKMARKED = "bookmarked-posts";
 23→    public static final String TAG_TITLE_DEFAULT = TAG_TITLE_FOLLOWED_SITES;
 24→    public static final String TAG_ENDPOINT_DEFAULT = FOLLOWING_PATH;
 25→
 26→    private String mTagSlug; // tag for API calls
 27→    private String mTagDisplayName; // tag for display, usually the same as the slug
 28→    private String mTagTitle; // title, used for default tags
 29→    private String mEndpoint; // endpoint for updating posts with this tag
 30→
 31→    private boolean mIsDefaultInMemoryTag;
 32→
 33→    public final ReaderTagType tagType;
 34→
 35→    public ReaderTag(String slug,
 36→                     String displayName,
 37→                     String title,
 38→                     String endpoint,
 39→                     ReaderTagType tagType) {
 40→        this(slug, displayName, title, endpoint, tagType, false);
 41→    }
 42→
 43→    public ReaderTag(String slug,
 44→                     String displayName,
 45→                     String title,
 46→                     String endpoint,
 47→                     ReaderTagType tagType,
 48→                     boolean isDefaultInMemoryTag) {
 49→        // we need a slug since it's used to uniquely ID the tag (including setting it as the
 50→        // primary key in the tag table)
 51→        if (TextUtils.isEmpty(slug)) {
 52→            if (tagType == ReaderTagType.BOOKMARKED) {
 53→                setTagSlug(TAG_SLUG_BOOKMARKED);
 54→            } else if (!TextUtils.isEmpty(title)) {
 55→                setTagSlug(ReaderUtils.sanitizeWithDashes(title));
 56→            } else {
 57→                setTagSlug(getTagSlugFromEndpoint(endpoint));
 58→            }
 59→        } else {
 60→            setTagSlug(slug);
 61→        }
 62→
 63→        setTagDisplayName(displayName);
 64→        setTagTitle(title);
 65→        setEndpoint(endpoint);
 66→        this.tagType = tagType;
 67→        mIsDefaultInMemoryTag = isDefaultInMemoryTag;
 68→    }
 69→
 70→    public String getEndpoint() {
 71→        return StringUtils.notNullStr(mEndpoint);
 72→    }
 73→
 74→    public void setEndpoint(String endpoint) {
 75→        this.mEndpoint = StringUtils.notNullStr(endpoint);
 76→    }
 77→
 78→    public String getTagTitle() {
 79→        return StringUtils.notNullStr(mTagTitle);
 80→    }
 81→
 82→    public void setTagTitle(String title) {
 83→        this.mTagTitle = StringUtils.notNullStr(title);
 84→    }
 85→
 86→    private boolean hasTagTitle() {
 87→        return !TextUtils.isEmpty(mTagTitle);
 88→    }
 89→
 90→    public String getTagDisplayName() {
 91→        return StringUtils.notNullStr(mTagDisplayName);
 92→    }
 93→
 94→    public void setTagDisplayName(String displayName) {
 95→        this.mTagDisplayName = StringUtils.notNullStr(displayName);
 96→    }
 97→
 98→    public String getTagSlug() {
 99→        return StringUtils.notNullStr(mTagSlug);
100→    }
101→
102→    private void setTagSlug(String slug) {
103→        this.mTagSlug = StringUtils.notNullStr(slug);
104→    }
105→
106→    /*
107→     * returns the tag name for use in the application log - if this is a default tag it returns
108→     * the full tag name, otherwise it abbreviates the tag name since exposing followed tags
109→     * in the log could be considered a privacy issue
110→     */
111→    public String getTagNameForLog() {
112→        String tagSlug = getTagSlug();
113→        if (tagType == ReaderTagType.DEFAULT) {
114→            return tagSlug;
115→        } else if (tagType == ReaderTagType.BOOKMARKED) {
116→            return ReaderTagType.BOOKMARKED.name();
117→        } else if (tagSlug.length() >= 6) {
118→            return tagSlug.substring(0, 3) + "...";
119→        } else if (tagSlug.length() >= 4) {
120→            return tagSlug.substring(0, 2) + "...";
121→        } else if (tagSlug.length() >= 2) {
122→            return tagSlug.substring(0, 1) + "...";
123→        } else {
124→            return "...";
125→        }
126→    }
127→
128→    /*
129→     * used to ensure a tag name is valid before adding it
130→     */
131→    @SuppressWarnings("RegExpRedundantEscape") private static final Pattern INVALID_CHARS =
132→            Pattern.compile("^.*[~#@*+%{}<>\\[\\]|\"\\_].*$");
133→
134→    public static boolean isValidTagName(String tagName) {
135→        return !TextUtils.isEmpty(tagName)
136→               && !INVALID_CHARS.matcher(tagName).matches();
137→    }
138→
139→    /*
140→     * extracts the tag slug from a valid read/tags/[mTagSlug]/posts endpoint
141→     */
142→    private static String getTagSlugFromEndpoint(final String endpoint) {
143→        if (TextUtils.isEmpty(endpoint)) {
144→            return "";
145→        }
146→
147→        // make sure passed endpoint is valid
148→        if (!endpoint.endsWith("/posts")) {
149→            return "";
150→        }
151→        int start = endpoint.indexOf("/read/tags/");
152→        if (start == -1) {
153→            return "";
154→        }
155→
156→        // skip "/read/tags/" then find the next "/"
157→        start += 11;
158→        int end = endpoint.indexOf("/", start);
159→        if (end == -1) {
160→            return "";
161→        }
162→
163→        return endpoint.substring(start, end);
164→    }
165→
166→    public static boolean isSameTag(ReaderTag tag1, ReaderTag tag2) {
167→        return tag1 != null && tag2 != null && tag1.tagType == tag2.tagType && tag1.getTagSlug()
168→                                                                                   .equalsIgnoreCase(tag2.getTagSlug());
169→    }
170→
171→    public boolean isPostsILike() {
172→        return tagType == ReaderTagType.DEFAULT && getEndpoint().endsWith(LIKED_PATH);
173→    }
174→
175→    public boolean isFollowedSites() {
176→        return tagType == ReaderTagType.DEFAULT && getEndpoint().endsWith(FOLLOWING_PATH);
177→    }
178→
179→    public boolean isDefaultInMemoryTag() {
180→        return tagType == ReaderTagType.DEFAULT && mIsDefaultInMemoryTag;
181→    }
182→
183→    public boolean isBookmarked() {
184→        return tagType == ReaderTagType.BOOKMARKED;
185→    }
186→
187→    public boolean isDiscover() {
188→        return tagType == ReaderTagType.DEFAULT && getEndpoint().endsWith(DISCOVER_PATH);
189→    }
190→
191→    public boolean isTagTopic() {
192→        String endpoint = getEndpoint();
193→        return endpoint.toLowerCase(Locale.ROOT).contains("/read/tags/");
194→    }
195→
196→    public boolean isP2() {
197→        String endpoint = getEndpoint();
198→        return endpoint.toLowerCase(Locale.ROOT).contains("/read/following/p2");
199→    }
200→
201→    public boolean isA8C() {
202→        String endpoint = getEndpoint();
203→        return endpoint.toLowerCase(Locale.ROOT).contains("/read/a8c");
204→    }
205→
206→    public boolean isFilterable() {
207→        return this.isFollowedSites() || this.isA8C() || this.isP2();
208→    }
209→
210→    public boolean isListTopic() {
211→        String endpoint = getEndpoint();
212→        return endpoint.toLowerCase(Locale.ROOT).contains("/read/list/");
213→    }
214→
215→    public Organization getOrganization() {
216→        if (this.isA8C()) {
217→            return Organization.A8C;
218→        } else if (this.isP2()) {
219→            return Organization.P2;
220→        } else if (this.isFollowedSites() || this.isDefaultInMemoryTag()) {
221→            return Organization.NO_ORGANIZATION;
222→        } else {
223→            return Organization.UNKNOWN;
224→        }
225→    }
226→
227→    public String getKeyString() {
228→        return tagType.toInt() + getTagSlug();
229→    }
230→
231→    /*
232→     * the label is the text displayed in the dropdown filter
233→     */
234→    @Override
235→    public String getLabel() {
236→        if (isTagDisplayNameAlphaNumeric()) {
237→            return getTagDisplayName().toLowerCase(Locale.ROOT);
238→        } else if (hasTagTitle()) {
239→            return getTagTitle();
240→        } else {
241→            return getTagDisplayName();
242→        }
243→    }
244→
245→    /*
246→     * returns true if the tag display name contains only alpha-numeric characters or hyphens
247→     */
248→    private boolean isTagDisplayNameAlphaNumeric() {
249→        if (TextUtils.isEmpty(mTagDisplayName)) {
250→            return false;
251→        }
252→
253→        for (int i = 0; i < mTagDisplayName.length(); i++) {
254→            char c = mTagDisplayName.charAt(i);
255→            if (!Character.isLetterOrDigit(c) && c != '-') {
256→                return false;
257→            }
258→        }
259→
260→        return true;
261→    }
262→
263→    /**
264→     * Local only tag used to identify post cards for the "discover" tab in the Reader.
265→     */
266→    public static ReaderTag createDiscoverPostCardsTag() {
267→        return new ReaderTag("", "", "", "", ReaderTagType.DISCOVER_POST_CARDS);
268→    }
269→
270→    @Override
271→    public boolean equals(Object object) {
272→        if (object instanceof ReaderTag) {
273→            ReaderTag tag = (ReaderTag) object;
274→            return (tag.tagType == this.tagType && tag.getLabel().equals(this.getLabel()));
275→        } else {
276→            return false;
277→        }
278→    }
279→}
