211→    private fun moveTrashedPostToDraft(post: PostModel) {
212→        /*
213→         * We need network connection to move a post to remote draft. We can technically move it to the local drafts
214→         * but that'll leave the trashed post in the remote which can be confusing.
215→         */
216→        if (!checkNetworkConnection.invoke()) {
217→            return
218→        }
219→        post.setStatus(DRAFT.toString())
220→        dispatcher.dispatch(PostActionBuilder.newPushPostAction(RemotePostPayload(post, site)))
221→
222→        val localPostId = LocalId(post.id)
223→        criticalPostActionTracker.add(localPostId, MOVING_POST_TO_DRAFT)
224→
225→        val snackBarHolder = SnackbarMessageHolder(
226→            message = UiStringRes(R.string.post_moving_to_draft),
227→            onDismissAction = {
228→                criticalPostActionTracker.remove(localPostId, MOVING_POST_TO_DRAFT)
229→            }
230→        )
231→        showSnackbar.invoke(snackBarHolder)
232→    }
