252→    private fun editPost(site: SiteModel, post: PostModel) {
253→        if (UploadService.isPostUploadingOrQueued(post)) {
254→            // If the post is uploading media, allow the media to continue uploading, but don't upload the
255→            // post itself when they finish (since we're about to edit it again)
256→            UploadService.cancelQueuedPostUpload(post)
257→        }
258→        triggerPostListAction.invoke(PostListAction.EditPost(site, post, loadAutoSaveRevision = false))
259→    }
