261→    fun deletePost(localPostId: Int) {
262→        // If post doesn't exist, nothing else to do
263→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
264→        criticalPostActionTracker.add(LocalId(post.id), DELETING_POST)
265→
266→        when {
267→            post.isLocalDraft -> {
268→                val pushId = PendingDraftsNotificationsUtils.makePendingDraftNotificationId(post.id)
269→                triggerPostListAction(DismissPendingNotification(pushId))
270→                dispatcher.dispatch(PostActionBuilder.newRemovePostAction(post))
271→            }
272→            else -> {
273→                dispatcher.dispatch(PostActionBuilder.newDeletePostAction(RemotePostPayload(post, site)))
274→            }
275→        }
276→    }
277→
278→    /**
279→     * This function handles a post being deleted and removed. Since deleting remote posts will trigger both delete
280→     * and remove actions we only want to remove the critical action when the post is actually successfully removed.
281→     *
282→     * It's possible to separate these into two methods that handles delete and remove. However, the fact that they
283→     * follow the same approach and the tricky nature of delete action makes combining the actions like so makes our
284→     * expectations clearer.
285→     */
286→    fun handlePostDeletedOrRemoved(localPostId: LocalId, isRemoved: Boolean, isError: Boolean) {
287→        if (criticalPostActionTracker.get(localPostId) != DELETING_POST) {
288→            /*
289→             * This is an unexpected action and either it has already been handled or another critical action has
290→             * been performed. In either case, safest action is to just ignore it.
291→             */
292→            return
293→        }
294→        if (isError) {
295→            showToast.invoke(ToastMessageHolder(R.string.error_deleting_post, Duration.SHORT))
296→        }
297→        if (isRemoved) {
298→            criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = DELETING_POST)
299→        }
300→    }
