 39→class EditorJetpackSocialViewModel @Inject constructor(
 40→    private val dispatcher: Dispatcher,
 41→    private val accountStore: AccountStore,
 42→    private val getPublicizeConnectionsForUserUseCase: GetPublicizeConnectionsForUserUseCase,
 43→    private val getJetpackSocialShareMessageUseCase: GetJetpackSocialShareMessageUseCase,
 44→    private val getJetpackSocialShareLimitStatusUseCase: GetJetpackSocialShareLimitStatusUseCase,
 45→    private val jetpackUiStateMapper: EditPostPublishSettingsJetpackSocialUiStateMapper,
 46→    private val postSocialSharingModelMapper: PostSocialSharingModelMapper,
 47→    private val publicizeTableWrapper: PublicizeTableWrapper,
 48→    private val appPrefsWrapper: AppPrefsWrapper,
 49→    private val siteStore: SiteStore,
 50→    private val jetpackSocialSharingTracker: JetpackSocialSharingTracker,
 51→    @Named(BG_THREAD) private val bgDispatcher: CoroutineDispatcher,
 52→) : ScopedViewModel(bgDispatcher) {
 53→    private lateinit var siteModel: SiteModel
 54→    private lateinit var editPostRepository: EditPostRepository
 55→
 56→    private val _jetpackSocialContainerVisibility = MutableLiveData<JetpackSocialContainerVisibility>()
 57→    val jetpackSocialContainerVisibility: LiveData<JetpackSocialContainerVisibility> = _jetpackSocialContainerVisibility
 58→
 59→    private val _jetpackSocialUiState = MutableLiveData<JetpackSocialUiState>()
 60→    val jetpackSocialUiState: LiveData<JetpackSocialUiState> = _jetpackSocialUiState
 61→
 62→    // this is a SingleLiveEvent so it should have one, and only one, observer (the Activity)
 63→    private val _actionEvents = SingleLiveEvent<ActionEvent>()
 64→    val actionEvents: LiveData<ActionEvent> = _actionEvents
 65→
 66→    private var jetpackSocialShareMessage = ""
 67→    private lateinit var shareLimit: ShareLimit
 68→    private val connections = mutableListOf<PostSocialConnection>()
 69→
 70→    var isStarted: Boolean = false
 71→
 72→    private var isLastActionOnResumeHandled = false
 73→
 74→    private val currentPost: PostImmutableModel?
 75→        get() = editPostRepository.getPost()
 76→
 77→    fun start(siteModel: SiteModel, editPostRepository: EditPostRepository) {
 78→        if (isStarted) return
 79→
 80→        dispatcher.register(this)
 81→
 82→        isStarted = true
 83→        this.siteModel = siteModel
 84→        this.editPostRepository = editPostRepository
 85→
 86→        startJetpackSocial()
 87→    }
 88→
 89→    private fun startJetpackSocial() {
 90→        if (shouldShowJetpackSocial()) {
 91→            launch {
 92→                shareLimit = getJetpackSocialShareLimitStatusUseCase.execute(siteModel)
 93→                loadConnections()
 94→                loadJetpackSocialIfSupported()
 95→            }
 96→        } else {
 97→            _jetpackSocialContainerVisibility.value = JetpackSocialContainerVisibility.ALL_HIDDEN
 98→        }
 99→    }
100→
101→    fun onResume(jetpackSocialFlow: JetpackSocialFlow) {
102→        _jetpackSocialUiState.value?.let { uiState ->
103→            if (uiState is JetpackSocialUiState.Loaded && uiState.showShareLimitUi) {
104→                jetpackSocialSharingTracker.trackShareLimitDisplayed(jetpackSocialFlow)
105→            } else if (uiState is JetpackSocialUiState.NoConnections) {
106→                trackAddConnectionCtaDisplayedIfVisible(jetpackSocialFlow)
107→            }
108→        }
109→        if (!isLastActionOnResumeHandled) {
110→            isLastActionOnResumeHandled = true
111→            when (actionEvents.value) {
112→                is ActionEvent.OpenSocialConnectionsList -> {
113→                    // When getting back from publicize connections screen, we should update connections to
114→                    // make sure we have the latest data.
115→                    launch {
116→                        updateConnections()
117→                        loadJetpackSocialIfSupported()
118→                    }
119→                }
120→
121→                is ActionEvent.OpenSubscribeJetpackSocial -> {
122→                    // We have to update SiteModel to make sure we have the latest data regarding user hired plans
123→                    dispatcher.dispatch(SiteActionBuilder.newFetchSiteAction(siteModel))
124→                }
125→
126→                else -> {
127→                    // Do nothing
128→                }
129→            }
130→        }
131→    }
132→
133→    private suspend fun loadConnections() {
134→        val publicizeConnections = getPublicizeConnectionsForUserUseCase.execute(
135→            siteId = siteModel.siteId,
136→            userId = accountStore.account.userId
137→        )
138→        connections.clear()
139→        connections.addAll(publicizeConnections.map { connection ->
140→            PostSocialConnection.fromPublicizeConnection(connection, false)
141→        })
142→        updateInitialConnectionListSharingStatus()
143→    }
144→
145→    private suspend fun updateConnections() {
146→        val publicizeConnections = getPublicizeConnectionsForUserUseCase.execute(
147→            siteId = siteModel.siteId,
148→            userId = accountStore.account.userId,
149→            shouldForceUpdate = false,
150→        )
151→        // Update connections list with new connections
152→        val currentConnectionIds = connections.map { it.connectionId }
153→        publicizeConnections.forEach { publicizeConnection ->
154→            if (currentConnectionIds.doesNotContain(publicizeConnection.connectionId)) {
155→                connections.add(PostSocialConnection.fromPublicizeConnection(publicizeConnection, false))
156→            }
157→        }
158→        // Update connections list with removed connections
159→        currentConnectionIds.forEach { currentConnectionId ->
160→            if (publicizeConnections.map { connection -> connection.connectionId }
161→                    .doesNotContain(currentConnectionId)) {
162→                connections.removeAll { connection -> connection.connectionId == currentConnectionId }
163→            }
164→        }
165→    }
166→
167→    private suspend fun loadJetpackSocialIfSupported() {
168→        if (!shouldShowJetpackSocial()) {
169→            _jetpackSocialContainerVisibility.postValue(JetpackSocialContainerVisibility.ALL_HIDDEN)
170→            return
