 90→    private static void requestPostsWithTag(final ReaderTag tag,
 91→                                            final UpdateAction updateAction,
 92→                                            final ReaderActions.UpdateResultListener resultListener) {
 93→        String path = getRelativeEndpointForTag(tag);
 94→        if (TextUtils.isEmpty(path)) {
 95→            resultListener.onUpdateResult(ReaderActions.UpdateResult.FAILED);
 96→            return;
 97→        }
 98→
 99→        StringBuilder sb = new StringBuilder(path);
100→
101→        // append #posts to retrieve
102→        sb.append("?number=").append(ReaderConstants.READER_MAX_POSTS_TO_REQUEST);
103→
104→        // return newest posts first (this is the default, but make it explicit since it's important)
105→        sb.append("&order=DESC");
106→
107→        String beforeDate;
108→        switch (updateAction) {
109→            case REQUEST_OLDER:
110→                // request posts older than the oldest existing post with this tag
111→                beforeDate = ReaderPostTable.getOldestDateWithTag(tag);
112→                break;
113→            case REQUEST_OLDER_THAN_GAP:
114→                // request posts older than the post with the gap marker for this tag
115→                beforeDate = ReaderPostTable.getGapMarkerDateForTag(tag);
116→                break;
117→            case REQUEST_NEWER:
118→            case REQUEST_REFRESH:
119→            default:
120→                beforeDate = null;
121→                break;
122→        }
123→        if (!TextUtils.isEmpty(beforeDate)) {
124→            sb.append("&before=").append(UrlUtils.urlEncode(beforeDate));
125→        }
126→
127→        sb.append("&meta=site,likes");
128→
129→        com.wordpress.rest.RestRequest.Listener listener = new RestRequest.Listener() {
130→            @Override
131→            public void onResponse(JSONObject jsonObject) {
132→                // remember when this tag was updated if newer posts were requested
133→                if (updateAction == UpdateAction.REQUEST_NEWER || updateAction == UpdateAction.REQUEST_REFRESH) {
134→                    ReaderTagTable.setTagLastUpdated(tag);
135→                }
136→                handleUpdatePostsResponse(tag, jsonObject, updateAction, resultListener);
137→            }
138→        };
139→        RestRequest.ErrorListener errorListener = new RestRequest.ErrorListener() {
140→            @Override
141→            public void onErrorResponse(VolleyError volleyError) {
142→                AppLog.e(AppLog.T.READER, volleyError);
143→                resultListener.onUpdateResult(ReaderActions.UpdateResult.FAILED);
144→            }
145→        };
146→
147→        WordPress.getRestClientUtilsV1_2().get(sb.toString(), null, null, listener, errorListener);
148→    }
