        val actual = tagProvider.promptIdTag("invalid-url")

        assertThat(actual).isEqualTo(BloggingPromptsPostTagProvider.BLOGGING_PROMPT_TAG)
    }

    @Test
    fun `Should return ReaderTag with correct properties when promptIdSearchReaderTag is called`() {
        whenever(readerUtilsWrapper.getTagFromTagUrl(any())).thenReturn(BLOGGING_PROMPT_ID_TAG)

        val actual = tagProvider.promptIdSearchReaderTag("valid-url")

        assertThat(actual.tagSlug).isEqualTo(BLOGGING_PROMPT_ID_TAG)
        assertThat(actual.tagType).isEqualTo(ReaderTagType.FOLLOWED)
        // The endpoint must contain "/read/tags/" for isTagTopic() to return true
        assertThat(actual.endpoint).contains("/read/tags/")
        assertThat(actual.isTagTopic).isTrue()
    }

    @Test
    fun `Should return ReaderTag with sanitized tag slug when promptIdSearchReaderTag is called`() {
        val tagWithSpaces = "daily prompt 1234"
        whenever(readerUtilsWrapper.getTagFromTagUrl(any())).thenReturn(tagWithSpaces)

        val actual = tagProvider.promptIdSearchReaderTag("valid-url")

        // Tag slug should be sanitized with dashes
        assertThat(actual.tagSlug).isEqualTo("daily-prompt-1234")
        assertThat(actual.isTagTopic).isTrue()
    }

    companion object {
        private const val BLOGGING_PROMPT_ID_TAG = "dailyprompt-1234"
    }
}"}

